const files = $input.all().map(i => i.json);

files.sort((a, b) => {
  const timeA = new Date(a.createdTime).getTime();
  const timeB = new Date(b.createdTime).getTime();
  return timeB - timeA; // más reciente primero
});

// devolver solo el más reciente
return [files[0]];

const file = $input.first().json;
const created = new Date(file.createdTime).getTime(); // timestamp en ms
const now = Date.now(); // timestamp actual en ms
const diffHours = (now - created) / (1000 * 60 * 60);

if (!file.empty && diffHours > 24) {
  return [
    {
      file: file.name,
      lastUpload: new Date(created).toISOString(),
      diffHours,
      isNotification: true,
    },
  ];
} else {
  return [
    {
      isNotification: false,
    },
  ];
}

