const items = $input.all();

// Si no hay items o el primero viene vacío
if (!items || items.length === 0 || Object.keys(items[0].json).length === 0) {
  return [{
    id: null,
    name: null,
    createdTime: null,
    empty: true
  }];
}

// Si hay resultados válidos
return items.map(i => ({ ...i.json, empty: false }));
